{
  "name": "elastic-connectors",
  "index_template": {
    "index_patterns": [
      ".elastic-connectors-v1"
    ],
    "_meta": {
      "description": "Built-in template for elastic-connectors",
      "managed": true
    }
  }
}
{
  "name": "elastic-connectors-sync-jobs",
  "index_template": {
    "index_patterns": [
      ".elastic-connectors-sync-jobs-v1"
    ],
    "_meta": {
      "description": "Built-in template for elastic-connectors-sync-jobs",
      "managed": true
    }
  }
}
{
  "name": "search-acl-filter",
  "index_template": {
    "index_patterns": [
      ".search-acl-filter-*"
    ],
    "template": {
      "settings": {
        "index": {
          "hidden": "true",
          "number_of_shards": "1",
          "number_of_replicas": "1"
        }
      }
    },
    "_meta": {
      "description": "Built-in template for access control indices",
      "managed": true
    }
  }
}

