=== elasticsearch-0 settings ===
{
  "cluster": {
    "initial_master_nodes": [
      "elasticsearch-0",
      "elasticsearch-1",
      "elasticsearch-2"
    ],
    "name": "es-cluster",
    "election": {
      "strategy": "supports_voting_only"
    }
  },
  "node": {
    "attr": {
      "transform": {
        "config_version": "10.0.0"
      },
      "xpack": {
        "installed": "true"
      },
      "ml": {
        "config_version": "11.0.0"
      }
    },
    "name": "elasticsearch-0",
    "roles": [
      "master",
      "data",
      "ingest"
    ]
  },
  "path": {
    "logs": "/usr/share/elasticsearch/logs",
    "home": "/usr/share/elasticsearch"
  },
  "discovery": {
    "seed_hosts": [
      "elasticsearch-headless"
    ]
  },
  "client": {
    "type": "node"
  },
  "http": {
    "compression": "false",
    "type": "security4",
    "type.default": "netty4"
  },
  "transport": {
    "type": "security4",
    "type.default": "netty4"
  },
  "xpack": {
    "security": {
      "http": {
        "ssl": {
          "enabled": "true"
        }
      },
      "enabled": "true",
      "transport": {
        "ssl": {
          "enabled": "true"
        }
      }
    }
  },
  "network": {
    "host": "0.0.0.0"
  }
}

